# recurrence
def T(n: int, k: int) -> int:
    if n == 0: return 1
    if k == 0 or k == n: return 2*T(n-1, 0) + 1
    if n == 2*k: return T(n-1, 0) + 1
    return T(n-1, k-1) + T(n-1, k)
for n in range(10): print([n], [T(n, k) for k in range(n + 1)])

